// tree.nodes are string IDs, not objects — just pass them as-is
function stripToTOC(nodes) {
  return nodes.map(node => ({
    node_id: node.node_id,
    title: node.title,
    start_index: node.start_index,
    end_index: node.end_index,
    description: node.summary,
    children: node.nodes || []  // keep as string IDs, LLM can still read them
  }));
}

output = {
  toc_json: JSON.stringify(stripToTOC(tree)),
  node_count: tree.length
};

const tree = {{postgresNode_817.output.queryResult[0].tree}};
const rawTextRaw = {{postgresNode_817.output.queryResult[0].raw_text}};
const nodeList = {{InstructorLLMNode_432.output.node_list}};

// Parse raw_text (stored as TEXT in DB)
const pages = typeof rawTextRaw === "string" ? JSON.parse(rawTextRaw) : rawTextRaw;

// Build flat node map from top-level tree array
const nodeMap = {};
for (const n of tree) {
  nodeMap[n.node_id] = n;
}

const selectedNodes = nodeList.map(id => nodeMap[id]).filter(Boolean);

const MAX_PAGES_PER_NODE = 2;    // hard cap — never more than 2 pages per node
const MAX_CHARS_PER_PAGE = 2000; // truncate very long pages

const retrieved = selectedNodes.map(node => {
  const startPage = (node.start_index || 1) - 1; // 0-based
  const rawEndPage = (node.end_index || node.start_index || 1) - 1;

  // Enforce max pages cap
  const endPage = Math.min(rawEndPage, startPage + MAX_PAGES_PER_NODE - 1, pages.length - 1);

  const pageSlices = pages
    .slice(startPage, endPage + 1)
    .map(p => p.length > MAX_CHARS_PER_PAGE ? p.slice(0, MAX_CHARS_PER_PAGE) + "..." : p);

  const pageContent = pageSlices.join("\n\n").trim();

  return {
    node_id: node.node_id,
    title: node.title,
    start_index: node.start_index,
    end_index: node.end_index,
    summary: node.summary,
    page_content: pageContent || node.summary
  };
});

const context = retrieved
  .map(n => `[Section: "${n.title}" | Pages: ${n.start_index}–${n.end_index}]\n${n.page_content}`)
  .join("\n\n---\n\n");

output = {
  context,
  retrieved_nodes: retrieved,
  total_chars: context.length
};
